import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"专享特权","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/exclusive-privileges.md","filePath":"zh-CN/account/exclusive-privileges.md"}'),i={name:"account/exclusive-privileges.md"};function o(n,a,d,s,h,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="专享特权" tabindex="-1">专享特权 <a class="header-anchor" href="#专享特权" aria-label="Permalink to &quot;专享特权&quot;">​</a></h1><p>「专享特权」展示账户当前已解锁的专属权益，以及可通过达成条件解锁的额外权益。入口在「我的」→ 蓝色专享特权卡片，或「我的」→「专享特权」。</p><h2 id="交易权益" tabindex="-1">交易权益 <a class="header-anchor" href="#交易权益" aria-label="Permalink to &quot;交易权益&quot;">​</a></h2><h3 id="终生免佣" tabindex="-1">终生免佣 <a class="header-anchor" href="#终生免佣" aria-label="Permalink to &quot;终生免佣&quot;">​</a></h3><ul><li><strong>港股终生免佣</strong>：港股股票、ETF 等交易佣金永久减免为 0</li><li><strong>美股终生免佣</strong>：美股股票、ETF 等交易佣金永久减免为 0</li></ul><p>「终生」指在长桥平台有效运营期间持续有效，不设到期时间；若平台规则有重大调整，会提前通知。所有权益绑定账户本人，不支持转让、赠送或出售。</p><p><strong>港股终生免佣范围</strong></p><ul><li>包含：港股证券户口发生证券交易买卖时产生的相关佣金费用</li><li>不包含：暗盘交易佣金、平台使用费、交易征费、交易费、交收费及印花税等第三方费用</li></ul><p><strong>美股终生免佣范围</strong></p><ul><li>包含：美股证券户口发生证券交易买卖时产生的相关佣金费用</li><li>不包含：美股期权交易佣金、平台使用费、交易征费、交易费、交收费等第三方费用</li></ul><p>详情请参阅长桥 App「我的」→「我的费率」。</p><h2 id="行情权益" tabindex="-1">行情权益 <a class="header-anchor" href="#行情权益" aria-label="Permalink to &quot;行情权益&quot;">​</a></h2><table tabindex="0"><thead><tr><th>权益</th><th>说明</th></tr></thead><tbody><tr><td>港股 L2</td><td>港交所 LV2 实时十档买卖盘深度行情</td></tr><tr><td>全美行情</td><td>全美综合报价，覆盖 NASDAQ、NYSE、CBOE 在内 16 家全美主流交易所和 FINRA TRF 场外数据（最新价、逐笔成交、成交量）</td></tr><tr><td>美股深度摆盘</td><td>60 档位买卖盘报价，覆盖盘前、盘中、盘后、夜盘全交易时段</td></tr></tbody></table><p><strong>港股 L2 地域限制</strong>：应港交所要求，L2 行情区分地域和设备类型。中国大陆移动端授权仅绑定单一设备，不可在多台设备同时使用；香港及其他地区无此限制。换手机后需重新激活绑定，进入「专享特权」或「行情权限」页面按提示操作，或联系客服协助。</p><h2 id="解锁方式" tabindex="-1">解锁方式 <a class="header-anchor" href="#解锁方式" aria-label="Permalink to &quot;解锁方式&quot;">​</a></h2><p>部分权益需完成资产或交易要求后，在「兑换商城」兑换激活：</p><ol><li>在「专享特权」页面查看待解锁权益的具体条件</li><li>完成对应条件（如达到指定交易量或持仓金额）</li><li>前往「我的」→「兑换商城」完成兑换</li></ol><h2 id="累计已省" tabindex="-1">累计已省 <a class="header-anchor" href="#累计已省" aria-label="Permalink to &quot;累计已省&quot;">​</a></h2><p>「我的」主页专享特权卡片上显示<strong>累计已省金额</strong>，统计港股终生免佣和美股终生免佣两大特权累计节省的交易佣金，自获得特权后的第一笔成交订单开始计算，免佣金额统一以港元计算。</p><h2 id="邀好友共享" tabindex="-1">邀好友共享 <a class="header-anchor" href="#邀好友共享" aria-label="Permalink to &quot;邀好友共享&quot;">​</a></h2><p>点击专享特权页面内的「邀好友共享」，生成专属邀请链接。好友通过链接注册并满足条件后，双方可同时获得额外权益奖励。</p><h2 id="特权细则" tabindex="-1">特权细则 <a class="header-anchor" href="#特权细则" aria-label="Permalink to &quot;特权细则&quot;">​</a></h2><p>点击「专享特权」页面右上角的**「特权细则」**，可查看各项权益的详细说明，包括免佣范围、行情授权说明等最新规则。建议在兑换或使用权益前先阅读相关细则。</p>',23)])])}const b=t(i,[["render",o]]);export{u as __pageData,b as default};
